1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells with only one neighbor each (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive with exactly 2 neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("should keep a live cell alive with exactly 3 neighbors (survival)", () => {
19	    const result = nextGeneration([[0, 1], [1, 1], [2, 1], [1, 2]]);
20	    expect(result).toContainEqual([1, 1]);
21	  });
22	  it.todo("should kill a live cell with 4 neighbors (overpopulation)");
23	  it.todo("should bring a dead cell to life with exactly 3 live neighbors (reproduction)");
24	  it.todo("should keep a block pattern unchanged (still life)");
25	  it.todo("should oscillate a blinker pattern (oscillator)");
26	});
27

1	export function nextGeneration(cells: [number, number][]): [number, number][] {
2	  const alive = new Set(cells.map(([x, y]) => `${x},${y}`));
3	
4	  const neighborCounts = new Map<string, number>();
5	
6	  for (const [x, y] of cells) {
7	    for (let dx = -1; dx <= 1; dx++) {
8	      for (let dy = -1; dy <= 1; dy++) {
9	        if (dx === 0 && dy === 0) continue;
10	        const key = `${x + dx},${y + dy}`;
11	        neighborCounts.set(key, (neighborCounts.get(key) || 0) + 1);
12	      }
13	    }
14	  }
15	
16	  const nextAliveCells: [number, number][] = [];
17	
18	  for (const [key, count] of neighborCounts) {
19	    if (count === 3 || (count === 2 && alive.has(key))) {
20	      const [x, y] = key.split(",").map(Number);
21	      nextAliveCells.push([x, y]);
22	    }
23	  }
24	
25	  return nextAliveCells;
26	}
